// MiPulse VPS API Handler
// Migrated and upgraded from MiSub (D1 Only)

const REPORTS_MAX_KEEP = 5000;
const ALERTS_MAX_KEEP = 1000;
const KV_KEY_SETTINGS = 'misub_settings'; // Maintaining key for compatibility if needed

// --- Utilities ---

function createJson(data, status = 200) {
    return new Response(JSON.stringify(data), { 
        status, 
        headers: { 'Content-Type': 'application/json' } 
    });
}

function createError(msg, status = 400) {
    return new Response(JSON.stringify({ error: msg, success: false }), { 
        status, 
        headers: { 'Content-Type': 'application/json' } 
    });
}

function nowIso() { return new Date().toISOString(); }

function normalizeString(value) {
    if (value === null || value === undefined) return '';
    return String(value).trim();
}

function clampNumber(value, min, max, fallback = null) {
    const num = Number(value);
    if (!Number.isFinite(num)) return fallback;
    return Math.min(max, Math.max(min, num));
}

async function computeSignature(secret, nodeId, timestamp, payloadCanonical) {
    const data = `${nodeId}.${timestamp}.${payloadCanonical}`;
    const key = await crypto.subtle.importKey(
        'raw',
        new TextEncoder().encode(secret),
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['sign']
    );
    const signature = await crypto.subtle.sign('HMAC', key, new TextEncoder().encode(data));
    return Array.from(new Uint8Array(signature)).map(b => b.toString(16).padStart(2, '0')).join('');
}

// --- Main Request Handler ---

export async function handleVpsRequest(path, request, env, auth) {
    const db = env.MIPULSE_DB;
    if (!db) return createError('D1 Binding (MIPULSE_DB) not found', 500);

    const url = new URL(request.url);
    const parts = path.split('/'); // vps/report, vps/nodes, etc.
    const method = request.method;

    // 1. 公共上报接口 (Public Report with HMAC)
    if (parts[1] === 'report' && method === 'POST') {
        return handleReport(request, db, env);
    }

    // 2. 脚本生成接口 (Script Generation)
    if (parts[1] === 'install' && method === 'GET') {
        return handleInstallScript(request, db, env);
    }
    if (parts[1] === 'uninstall' && method === 'GET') {
        return handleUninstallScript(request, db, env);
    }
    if (parts[1] === 'config' && method === 'GET') {
        return handleNodeConfig(request, db, env);
    }

    // 3. 公开展示页设计 (Public Snapshot)
    if (parts[1] === 'public' && method === 'GET') {
        return handlePublicSnapshot(request, db, env);
    }

    // --- 需要管理员权限 (Auth Required) ---
    if (!auth) return createError('Unauthorized', 401);

    // 4. 节点管理 (Nodes Management)
    if (parts[1] === 'nodes') {
        if (method === 'GET') {
            if (parts[2]) return handleGetNodeDetail(parts[2], db, env);
            return handleListNodes(db, env);
        }
        if (method === 'POST') return handleCreateNode(request, db, env);
        if (method === 'PUT' && parts[2]) return handleUpdateNode(parts[2], request, db, env);
        if (method === 'DELETE' && parts[2]) return handleDeleteNode(parts[2], db, env);
    }

    // 5. 告警管理 (Alerts)
    if (parts[1] === 'alerts') {
        if (method === 'GET') return handleListAlerts(db);
        if (method === 'DELETE') return handleClearAlerts(db);
    }

    // 6. 拨测目标管理 (Network Targets)
    if (parts[1] === 'targets') {
        if (method === 'GET') return handleListTargets(url.searchParams.get('nodeId'), db);
        if (method === 'POST') return handleCreateTarget(request, db);
        if (method === 'PUT' && parts[2]) return handleUpdateTarget(parts[2], request, db);
        if (method === 'DELETE' && parts[2]) return handleDeleteTarget(parts[2], db);
    }

    return createError('Not Found', 404);
}

// --- Implementation Logic ---

async function handleReport(request, db, env) {
    let payload;
    let rawBody = '';
    try {
        rawBody = await request.text();
        payload = rawBody ? JSON.parse(rawBody) : null;
    } catch {
        return createError('Invalid JSON', 400);
    }

    const nodeId = normalizeString(request.headers.get('x-node-id') || payload?.nodeId);
    const nodeSecret = normalizeString(request.headers.get('x-node-secret') || payload?.secret);
    const signature = normalizeString(request.headers.get('x-node-signature') || payload?.signature);
    const signatureTs = normalizeString(request.headers.get('x-node-timestamp') || payload?.timestamp);

    if (!nodeId) return createError('Missing node id', 401);

    const node = await db.prepare('SELECT * FROM vps_nodes WHERE id = ?').bind(nodeId).first();
    if (!node) return createError('Node not found', 404);
    if (!node.enabled) return createError('Node disabled', 403);

    // Signature Verification
    if (signature && signatureTs) {
        const expected = await computeSignature(node.secret, node.id, signatureTs, rawBody);
        if (expected !== signature) return createError('Invalid signature', 401);
    } else if (node.secret !== nodeSecret) {
        return createError('Unauthorized', 401);
    }

    const report = payload.report || payload;
    const reportedAt = report.reportedAt || nowIso();

    // 1. Save Report Record
    const reportId = crypto.randomUUID();
    await db.prepare(`
        INSERT INTO vps_reports (id, node_id, reported_at, created_at, data)
        VALUES (?, ?, ?, ?, ?)
    `).bind(reportId, nodeId, reportedAt, nowIso(), JSON.stringify(report)).run();

    // 2. Prune old reports
    await db.prepare('DELETE FROM vps_reports WHERE reported_at < DATETIME("now", "-30 days")').run();

    // 3. Update Node Status & Last Report
    const traffic = report.traffic || {};
    const lastReport = {
        cpuPercent: report.cpu?.usage || 0,
        memPercent: report.mem?.usage || 0,
        diskPercent: report.disk?.usage || 0,
        load1: report.load?.load1 || 0,
        traffic: traffic,
        network: report.network || null,
        ip: request.headers.get('CF-Connecting-IP') || ''
    };

    await db.prepare(`
        UPDATE vps_nodes 
        SET status = "online", 
            last_seen_at = ?, 
            last_report_json = ?,
            country_code = ?,
            updated_at = ?
        WHERE id = ?
    `).bind(reportedAt, JSON.stringify(lastReport), request.cf?.country || '', nowIso(), nodeId).run();

    // 4. Alert Logic (Simplified for now, can expand later)
    if (lastReport.cpuPercent > 95 || lastReport.memPercent > 95) {
        await db.prepare(`
            INSERT INTO vps_alerts (id, node_id, type, message, created_at)
            VALUES (?, ?, ?, ?, ?)
        `).bind(crypto.randomUUID(), nodeId, 'overload', `Node ${node.name} resources high: CPU ${lastReport.cpuPercent}%, MEM ${lastReport.memPercent}%`, nowIso()).run();
    }

    // 5. Global Heartbeat Cleanup (Mark others as offline if stale)
    await db.prepare(`
        UPDATE vps_nodes 
        SET status = "offline" 
        WHERE last_seen_at < DATETIME("now", "-10 minutes") AND status = "online"
    `).run();

    return createJson({ success: true });
}

async function handleListNodes(db) {
    const { results } = await db.prepare('SELECT * FROM vps_nodes ORDER BY created_at DESC').all();
    const data = results.map(row => ({
        ...row,
        enabled: row.enabled === 1,
        useGlobalTargets: row.use_global_targets === 1,
        lastReport: row.last_report_json ? JSON.parse(row.last_report_json) : null
    }));
    return createJson({ success: true, data: { data } });
}

async function handleCreateNode(request, db) {
    const body = await request.json();
    const id = crypto.randomUUID();
    const secret = body.secret || crypto.randomUUID();
    
    await db.prepare(`
        INSERT INTO vps_nodes (id, name, tag, group_tag, region, description, secret, status, enabled, use_global_targets, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(id, body.name, body.tag, body.groupTag, body.region, body.description, secret, 'offline', body.enabled ? 1 : 0, body.useGlobalTargets ? 1 : 0, nowIso(), nowIso()).run();

    return createJson({ success: true, id, secret });
}

async function handleUpdateNode(id, request, db) {
    const body = await request.json();
    await db.prepare(`
        UPDATE vps_nodes 
        SET name=?, tag=?, group_tag=?, region=?, description=?, enabled=?, use_global_targets=?, updated_at=?
        WHERE id = ?
    `).bind(body.name, body.tag, body.groupTag, body.region, body.description, body.enabled ? 1 : 0, body.useGlobalTargets ? 1 : 0, nowIso(), id).run();
    return createJson({ success: true });
}

async function handleDeleteNode(id, db) {
    await db.prepare('DELETE FROM vps_nodes WHERE id = ?').bind(id).run();
    await db.prepare('DELETE FROM vps_reports WHERE node_id = ?').bind(id).run();
    await db.prepare('DELETE FROM vps_alerts WHERE node_id = ?').bind(id).run();
    return createJson({ success: true });
}

async function handleGetNodeDetail(id, db) {
    const node = await db.prepare('SELECT * FROM vps_nodes WHERE id = ?').bind(id).first();
    if (!node) return createError('Node not found', 404);

    const { results: reports } = await db.prepare('SELECT data FROM vps_reports WHERE node_id = ? ORDER BY reported_at DESC LIMIT 100').bind(id).all();
    const { results: targets } = await db.prepare('SELECT * FROM vps_network_targets WHERE node_id = ? OR node_id = "global"').bind(id).all();

    return createJson({ 
        success: true, 
        data: {
            data: { ...node, lastReport: node.last_report_json ? JSON.parse(node.last_report_json) : null },
            reports: reports.map(r => JSON.parse(r.data)),
            targets: targets.map(t => ({ ...t, enabled: t.enabled === 1 }))
        } 
    });
}

async function handlePublicSnapshot(request, db) {
    const { results } = await db.prepare('SELECT id, name, tag, group_tag, region, country_code, status, last_report_json, last_seen_at FROM vps_nodes WHERE enabled = 1').all();
    const data = results.map(node => {
        const lastReport = node.last_report_json ? JSON.parse(node.last_report_json) : null;
        // Strip sensitive info if needed
        return {
            ...node,
            latest: lastReport
        };
    });
    return createJson({ success: true, data });
}

// --- Script Generation ---

function handleInstallScript(request, db, env) {
    const url = new URL(request.url);
    const nodeId = url.searchParams.get('nodeId');
    const secret = url.searchParams.get('secret');
    const reportUrl = `${url.origin}/api/vps/report`;

    const script = `#!/bin/bash
# MiPulse VPS Probe Installer
set -e
NODE_ID="${nodeId}"
NODE_SECRET="${secret}"
REPORT_URL="${reportUrl}"

echo "Installing MiPulse Probe for node: $NODE_ID"
# ... (simplified script for now, will bring full bash logic from MiSub in separate file or task)
`;
    return new Response(script, { headers: { 'Content-Type': 'text/plain' } });
}

async function handleUninstallScript(request, db) {
    const script = `#!/bin/bash
echo "Uninstalling MiPulse Probe..."
systemctl stop mipulse-probe.timer || true
rm /usr/local/bin/mipulse-probe.sh || true
`;
    return new Response(script, { headers: { 'Content-Type': 'text/plain' } });
}

async function handleNodeConfig(request, db) {
    // Return custom environmental config for the probe
    return createJson({ interval: 60, targets: [] });
}

// --- Alerts ---

async function handleListAlerts(db) {
    const { results } = await db.prepare('SELECT * FROM vps_alerts ORDER BY created_at DESC LIMIT 100').all();
    return createJson({ success: true, data: { data: results } });
}

async function handleClearAlerts(db) {
    await db.prepare('DELETE FROM vps_alerts').run();
    return createJson({ success: true });
}

// --- Targets ---

async function handleListTargets(nodeId, db) {
    const query = nodeId ? 'SELECT * FROM vps_network_targets WHERE node_id = ?' : 'SELECT * FROM vps_network_targets';
    const params = nodeId ? [nodeId] : [];
    const { results } = await db.prepare(query).bind(...params).all();
    return createJson({ success: true, data: results });
}

async function handleCreateTarget(request, db) {
    const body = await request.json();
    const id = crypto.randomUUID();
    await db.prepare(`
        INSERT INTO vps_network_targets (id, node_id, type, target, name, scheme, port, path, enabled, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).bind(id, body.nodeId || 'global', body.type, body.target, body.name, body.scheme || 'https', body.port, body.path || '/', body.enabled ? 1 : 0, nowIso(), nowIso()).run();
    return createJson({ success: true, id });
}
